import json
import re
from typing import Any, Optional
from pydantic import BaseModel, ValidationError
import logging

logger = logging.getLogger(__name__)

class OutputNormalizer:
    """
    Normalizes raw LLM outputs into consistent structured formats.
    Handles common inconsistencies: markdown wrapping, trailing text,
    missing fields, and type coercion.
    """

    def __init__(self, schema: type[BaseModel]):
        self.schema = schema

    def extract_json(self, raw: str) -> Optional[dict]:
        """Extract JSON from raw text, handling markdown fences and trailing content."""
        # Try direct parse first
        try:
            return json.loads(raw.strip())
        except json.JSONDecodeError:
            pass

        # Strip markdown code fences
        fence_pattern = r"```(?:json)?\s*([\s\S]*?)```"
        match = re.search(fence_pattern, raw, re.IGNORECASE)
        if match:
            try:
                return json.loads(match.group(1).strip())
            except json.JSONDecodeError:
                pass

        # Find first JSON object in text
        brace_pattern = r"\{[\s\S]*\}"
        match = re.search(brace_pattern, raw)
        if match:
            try:
                return json.loads(match.group(0))
            except json.JSONDecodeError:
                pass

        logger.warning(f"Could not extract JSON from output: {raw[:200]}")
        return None

    def normalize(self, raw: str, defaults: dict = {}) -> Optional[BaseModel]:
        """Normalize raw output into a validated schema instance."""
        data = self.extract_json(raw)
        if data is None:
            return None

        # Apply defaults for missing optional fields
        merged = {**defaults, **data}

        # Coerce common type mismatches
        for field_name, field_info in self.schema.model_fields.items():
            if field_name in merged:
                val = merged[field_name]
                # Coerce string booleans
                if field_info.annotation == bool and isinstance(val, str):
                    merged[field_name] = val.lower() in ("true", "yes", "1")
                # Coerce string numbers
                if field_info.annotation == float and isinstance(val, str):
                    try:
                        merged[field_name] = float(val)
                    except ValueError:
                        pass

        try:
            return self.schema(**merged)
        except ValidationError as e:
            logger.error(f"Schema validation failed after normalization: {e}")
            return None

# Usage example
from pydantic import BaseModel
from typing import Literal

class AgentOutput(BaseModel):
    action: Literal["search", "summarize", "escalate"]
    confidence: float
    reasoning: str

normalizer = OutputNormalizer(AgentOutput)

# These all normalize to the same structure:
raw1 = '{"action": "search", "confidence": 0.9, "reasoning": "Need more data"}'
raw2 = '```json\n{"action": "search", "confidence": "0.9", "reasoning": "Need more data"}\n```'
raw3 = 'Here is my response: {"action": "search", "confidence": 0.9, "reasoning": "Need more data"}'

for raw in [raw1, raw2, raw3]:
    result = normalizer.normalize(raw)
    print(result)  # All produce identical AgentOutput instances
